module RefModule(
    output reg Q,
    input D,
    input C,
    input R
);
    parameter [0:0] INIT = 1'b0;
    initial Q = INIT;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge C or negedge R or posedge dbg_halt)
        if (!R)
            Q <= 1'b0;
        else 
            Q <= D;
endmodule
